// Validate + normalise. Prefer fresh Airtable record; fall back to webhook payload if Airtable lookup failed.
const webhook = $('Webhook — Airtable deal').first().json;
// n8n webhook puts the body under .body when responseMode=lastNode
const payload = webhook.body || webhook;
const airtableResp = $json;
const hasAirtableFields = airtableResp && airtableResp.fields && !airtableResp.error;
const fields = hasAirtableFields ? airtableResp.fields : (payload.fields || {});
const record_id = (hasAirtableFields ? airtableResp.id : null) || payload.record_id || null;
const deal_id = fields['Deal ID'] || payload.deal_id || null;

const pick = (k) => (fields[k] !== undefined && fields[k] !== '') ? fields[k] : null;
const pickNum = (k) => { const v = pick(k); return v === null ? null : Number(v); };

const company_name = pick('Company Name');
const website = pick('Website');
const industry = pick('Industry');
const employee_count = pickNum('Employee Count');
const funding_stage = pick('Funding Stage');
const funding_amount = pickNum('Funding Amount');
const deal_stage = pick('Deal Stage');
const ae_owner = pick('AE Owner');
const deal_value_eur = pickNum('Deal Value (EUR)');
const current_fpa_tool = pick('Current FP&A Tool');
const notes = pick('Notes');

// Domain extraction for Hunter / Firecrawl
let domain = null;
if (website) {
  try { domain = new URL(website.startsWith('http') ? website : `https://${website}`).hostname.replace(/^www\./, ''); }
  catch { domain = null; }
}

const missing = [];
if (!company_name) missing.push('company_name');
if (!website) missing.push('website');
if (!industry) missing.push('industry');

// Build a short company description for the RAG embedding
const description = [company_name, industry, current_fpa_tool && `currently using ${current_fpa_tool}`, funding_stage && `${funding_stage} stage`, employee_count && `${employee_count} employees`, notes].filter(Boolean).join(' · ');

if (!company_name) {
  // Hard stop — without a company name the workflow cannot proceed. Emit an error envelope.
  return [{ json: { _hard_error: 'company_name_missing', record_id, deal_id, raw_fields: fields } }];
}

return [{ json: {
  record_id, deal_id, airtable_lookup_ok: hasAirtableFields,
  company_name, website, domain, industry, employee_count, funding_stage, funding_amount,
  deal_stage, ae_owner, deal_value_eur, current_fpa_tool, notes,
  description, missing_fields: missing,
  has_website: !!website, has_domain: !!domain
} }];

