// Calculate deterministic ICP score per MASTER §5 weights (translated from Python).
// Then assemble the consolidated enrichment payload.
const deal = $('Code — validate + normalise').first().json;
const items = $input.all();
// Multiplex order matches connection input index: [0]=Firecrawl, [1]=Hunter.io, [2]=Supabase RAG
const firecrawlResp = items[0]?.json || {};
const hunterResp = items[1]?.json || {};
const ragResp = items[2]?.json || [];

// --- Firecrawl extract ---
const stripNoise = (s) => String(s || '').replace(/<\/?[^>]+(>|$)/g, ' ').replace(/\s+/g, ' ').trim();
const siteMd = firecrawlResp?.data?.markdown || firecrawlResp?.markdown || '';
const website_excerpt = siteMd ? stripNoise(siteMd).slice(0, 1500) : null;

// --- Hunter extract (best-effort; Hunter response shape: {data:{...}}) ---
const h = hunterResp?.data || {};
const hunter_company = h?.organization || h?.name || null;
const hunter_employees = h?.metrics?.employees || h?.employees || null;
const hunter_industry = h?.industry || h?.tags?.[0] || null;
const hunter_tech = Array.isArray(h?.technologies) ? h.technologies : (Array.isArray(h?.tech) ? h.tech : []);
const hunter_hq = h?.location || h?.city || null;

// --- RAG extract: top signals relevant to this prospect's likely FP&A stack ---
const rag = Array.isArray(ragResp) ? ragResp : (ragResp?.results || []);
const relevant_signals = rag.slice(0, 5).map(r => ({
  competitor_name: r.competitor_name, signal_type: r.signal_type,
  headline: (r.content || '').slice(0, 240), source_url: r.source_url, scraped_at: r.scraped_at,
  similarity: r.similarity
}));

// --- ICP scoring (deterministic, matches MASTER §5) ---
function icpScore(d, hunter) {
  const industry = String(d.industry || hunter.industry || '').toLowerCase();
  const indBand = /saas|software|tech/.test(industry) ? 100
               : /non.?profit|b2c|consumer|toys|retail consumer/.test(industry) ? 0
               : 50;
  const employees = Number(d.employee_count || hunter.employees || 0);
  const empBand = (employees >= 50 && employees <= 500) ? 100
               : (employees > 500 && employees <= 2000) ? 50
               : 0;
  const fund = String(d.funding_stage || '').toLowerCase();
  const fundBand = /series\s*a|series\s*b|series\s*c/.test(fund) ? 100
                 : /seed|series\s*d|series\s*e|series\s*f|growth equity/.test(fund) ? 50
                 : 0;
  const tool = String(d.current_fpa_tool || '').toLowerCase();
  const toolBand = (!tool || tool === 'unknown') ? 50
                 : /excel|sheet|google sheet|quickbooks/.test(tool) ? 100
                 : /anaplan|workday|pigment|planful|vena|adaptive|oracle|sap/.test(tool) ? 0
                 : 50;
  const sigStr = String((d.notes || '') + ' ' + (Array.isArray(hunter.tech) ? hunter.tech.join(' ') : '')).toLowerCase();
  const teamBand = /fp&a hire|finance hire|controller posting|head of fp&a|vp finance hire/.test(sigStr) ? 100
                 : /cfo|head of finance|vp finance|finance lead/.test(sigStr) ? 50
                 : 0;
  const total = indBand*0.30 + empBand*0.20 + fundBand*0.20 + toolBand*0.15 + teamBand*0.15;
  const score = Math.round(total);
  return { score, band: score >= 70 ? 'Green' : score >= 40 ? 'Amber' : 'Red',
    breakdown: { industry: indBand, employee_count: empBand, funding_stage: fundBand, fpa_tool: toolBand, finance_team: teamBand } };
}

const icp = icpScore(deal, { industry: hunter_industry, employees: hunter_employees, tech: hunter_tech });

// --- Source success flags ---
const sources_ok = {
  firecrawl: !!website_excerpt,
  hunter: !!hunter_company,
  rag: relevant_signals.length > 0
};

return [{ json: {
  ...deal,
  enrichment_sources: { website_excerpt, hunter_company, hunter_employees, hunter_industry, hunter_tech, hunter_hq, relevant_signals },
  icp,
  sources_ok,
  enrichment_started_at: new Date().toISOString()
} }];

const llm = $json;
const upstream = $('Code — ICP score + merge').first().json;
let enrichment, parseError = null;
try {
  let text = llm?.content?.[0]?.text;
  if (!text) throw new Error('no_content_in_anthropic_response');
  // Strip markdown code fences that Sonnet sometimes wraps JSON in (mirrors Scenario A v21 fix)
  text = String(text).trim();
  const fence = text.match(/^```(?:json)?\s*\n?([\s\S]*?)\n?```\s*$/);
  if (fence) text = fence[1].trim();
  try {
    enrichment = JSON.parse(text);
  } catch (parseErr) {
    // Graceful repair for truncated Sonnet output (mirrors Scenario A v26 fix)
    let repaired = text;
    const lastValidEnd = Math.max(repaired.lastIndexOf('}'), repaired.lastIndexOf(']'));
    if (lastValidEnd > 0) repaired = repaired.slice(0, lastValidEnd + 1);
    let depth = 0; let inStr = false; let esc = false;
    for (const ch of repaired) {
      if (esc) { esc = false; continue; }
      if (ch === '\\') { esc = true; continue; }
      if (ch === '"') inStr = !inStr;
      else if (!inStr && (ch === '{' || ch === '[')) depth++;
      else if (!inStr && (ch === '}' || ch === ']')) depth--;
    }
    while (depth > 0) { repaired += '}'; depth--; }
    enrichment = JSON.parse(repaired);
    parseError = `recovered after truncation: ${parseErr.message}`;
  }
} catch (e) { parseError = e.message; enrichment = null; }

// Always trust the deterministic ICP score; if Sonnet drifted, overwrite.
const trustedIcp = upstream.icp;

if (!enrichment) {
  enrichment = {
    airtable_deal_id: upstream.deal_id || upstream.record_id || null,
    company_name: upstream.company_name,
    company_overview: null, estimated_revenue: null, headcount: upstream.employee_count || null,
    funding_stage: upstream.funding_stage || null, funding_amount: null, key_decision_makers: [],
    current_fpa_stack: upstream.current_fpa_tool || null, tech_stack: upstream.enrichment_sources?.hunter_tech || [],
    icp_score: trustedIcp?.score, icp_band: trustedIcp?.band, icp_score_breakdown: trustedIcp?.breakdown,
    why_they_might_buy: null, competitive_signals_summary: null,
    ae_action_items: ['Manual review — Sonnet enrichment failed. See Langfuse trace.']
  };
} else {
  enrichment.icp_score = trustedIcp?.score;
  enrichment.icp_band = trustedIcp?.band;
  enrichment.icp_score_breakdown = trustedIcp?.breakdown;
  if (!enrichment.airtable_deal_id) enrichment.airtable_deal_id = upstream.deal_id || upstream.record_id;
  if (!enrichment.company_name) enrichment.company_name = upstream.company_name;
  if (!Array.isArray(enrichment.ae_action_items) || enrichment.ae_action_items.length === 0) {
    enrichment.ae_action_items = ['Manual review — Sonnet returned no action items.'];
  }
}

// Status logic — driven by the deterministic ICP score and presence of company_name.
// MASTER §5: enrichment_status in (Complete, Partial, Failed).
//   - ICP score missing/invalid                              -> Failed
//   - ICP score valid + company_name present + all optional  -> Complete
//   - ICP score valid + company_name present + some optional -> Partial
//   - ICP score valid but company_name missing                -> Failed
const optional = ['company_overview','headcount','funding_stage','funding_amount','current_fpa_stack','why_they_might_buy'];
const populated = optional.filter(k => enrichment[k] !== null && enrichment[k] !== undefined && enrichment[k] !== '').length;
enrichment.data_confidence = Math.round((populated / optional.length) * 100);

const icpScoreOk = typeof trustedIcp?.score === 'number' && trustedIcp.score >= 0 && trustedIcp.score <= 100;
const companyOk  = typeof enrichment.company_name === 'string' && enrichment.company_name.trim().length > 0;
if (!icpScoreOk || !companyOk) {
  enrichment.enrichment_status = 'Failed';
} else if (populated === optional.length) {
  enrichment.enrichment_status = 'Complete';
} else {
  enrichment.enrichment_status = 'Partial';
}

return [{ json: {
  enrichment, deal: upstream, parse_error: parseError,
  enriched_at: new Date().toISOString()
} }];

// Render the deal-notification Block Kit (see n8n/slack_deal_notification_block_kit.json).
const e = $('Code — parse + validate').first().json.enrichment;
const d = $('Code — parse + validate').first().json.deal;
const confEmoji = (c) => c >= 80 ? '✅' : c >= 50 ? '⚠️' : '🟥';
const bandEmoji = (b) => b === 'Green' ? '🟢' : b === 'Amber' ? '🟡' : '🔴';
const AIRTABLE_DEALS_TABLE_ID = 'tblKML2oup6YpKHAw';
const airtableUrl = `https://airtable.com/${$('Config').first().json.airtable_base_id}/${AIRTABLE_DEALS_TABLE_ID}/${d.record_id || ''}`;
const BATTLECARD_NOTION_URLS = {
  Pigment:    'https://www.notion.so/354cab25fcdb818ba2fdc0ac249f8515',
  Anaplan:    'https://www.notion.so/354cab25fcdb81c0bfefc1cab7d1e637',
  Planful:    'https://www.notion.so/354cab25fcdb814791f0c4535059021e',
  Drivetrain: 'https://www.notion.so/354cab25fcdb81abaf92d7ee69630f2e',
  Vena:       'https://www.notion.so/354cab25fcdb81f6a99ae7f5f0d86442'
};
const battlecardCompetitor = (e.competitive_signals_summary || '').match(/\b(Pigment|Anaplan|Planful|Drivetrain|Vena)\b/i)?.[0] || 'Pigment';
const battlecardUrl = BATTLECARD_NOTION_URLS[battlecardCompetitor] || 'https://www.notion.so/354cab25fcdb815db9a3d396b412a0ec';
const dealValue = d.deal_value_eur ? `€${d.deal_value_eur.toLocaleString('en-GB')}/yr` : 'unspecified';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: `📊 Deal Intelligence Ready — ${e.company_name}`, emoji: true } });
blocks.push({ type: 'context', elements: [
  { type: 'mrkdwn', text: `Qualified by: *${d.ae_owner || 'unknown'}*  ·  Deal: *${dealValue}*  ·  ${d.deal_id || d.record_id || ''}` }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: `*Company:*\n${e.company_name}` },
  { type: 'mrkdwn', text: `*Employees:*\n${e.headcount || '—'}` },
  { type: 'mrkdwn', text: `*Stage:*\n${e.funding_stage || '—'}` },
  { type: 'mrkdwn', text: `*Revenue:*\n${e.estimated_revenue || '—'}` },
  { type: 'mrkdwn', text: `*Industry:*\n${d.industry || '—'}` },
  { type: 'mrkdwn', text: `*HQ:*\n${d.enrichment_sources?.hunter_hq || '—'}` }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🎯 ICP Score: ${e.icp_score}/100  ${bandEmoji(e.icp_band)} ${e.icp_band}*\n*Current FP&A:* ${e.current_fpa_stack || '_unknown_'}\n*Decision maker:* ${(e.key_decision_makers && e.key_decision_makers[0]) ? `${e.key_decision_makers[0].title} — ${e.key_decision_makers[0].name}` : '_to investigate_'}` } });
if (e.why_they_might_buy) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Why they might buy:*\n${e.why_they_might_buy}` } });
}
if (e.competitive_signals_summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `🔴 *Watch:* ${e.competitive_signals_summary}` } });
}
if (Array.isArray(e.ae_action_items) && e.ae_action_items.length) {
  const items = e.ae_action_items.map(a => `• ${a}`).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*🎯 AE next steps*\n${items}` } });
}
blocks.push({ type: 'actions', elements: [
  { type: 'button', style: 'primary', text: { type: 'plain_text', text: 'Open in Airtable' }, url: airtableUrl },
  { type: 'button', text: { type: 'plain_text', text: `View ${battlecardCompetitor} battlecard` }, url: battlecardUrl },
  { type: 'button', style: 'danger', text: { type: 'plain_text', text: 'Mark contacted' }, url: airtableUrl }
] });
blocks.push({ type: 'context', elements: [
  { type: 'mrkdwn', text: `Data confidence: *${e.data_confidence}%* ${confEmoji(e.data_confidence)}  ·  Enrichment: *${e.enrichment_status}*  ·  ${e.data_confidence < 40 ? '⚠️ Partial — please add company website to CRM.' : ''}` }
] });

return [{ json: { enrichment: e, deal: d, slack_payload: { text: `📊 Deal Intelligence Ready — ${e.company_name}`, blocks } } }];

